Какая из предложенных проблем содержится в коде компонента?
```jsx
class Select extends React.Component {
  handleClick = (item) => (e) => {
    e.preventDefault();
    const { onClick } = this.props;
    onClick(item);
  }
  render() {
    const { items } = this.props;
    if (!items) {
      return null;
    }
    return (
      <div>
        {items.map((item) => (
          <div key={item.id} onClick={this.handleClick(item)}>{item.name}</div>
        ))}
      </div>
    );
  }
}

// Пример использования Select:
